export function getAllChapters(): Chapter[] {
  return bookData.parts.flatMap(p => p.chapters);
}

export function searchContent(query: string): Chapter[] {
  if (!query.trim()) return [];
  const q = query.toLowerCase().trim();
  return getAllChapters().filter(ch => {
    const searchable = [
      ch.title,
      ch.subtitle,
      ch.openingQuote,
      ch.closingLine,
      ...ch.sections.map(s => s.title + " " + s.content),
      ...ch.takeaways.map(t => t.text),
      ...ch.keywords
    ].join(" ").toLowerCase();
    return searchable.includes(q);
  });
}

export function getPartForChapter(chapterId: string): Part | undefined {
  return bookData.parts.find(p => p.chapters.some(c => c.id === chapterId));
}
